.carte {
  /* Contenu */
  width: 300px;
  height: 200px;

  /* Padding : espace intérieur (entre contenu et bordure) */
  padding: 16px;          /* tous les côtés */
  padding: 8px 16px;      /* haut/bas  gauche/droite */
  padding-top: 8px;       /* côté par côté */

  /* Bordure */
  border: 2px solid #e5e7eb;
  border-radius: 8px;     /* coins arrondis */

  /* Marge : espace extérieur (entre éléments) */
  margin: 16px auto;      /* auto centre horizontalement */

  /* box-sizing recommandé : inclut padding dans la width */
  box-sizing: border-box;
}
